form:Form.form:Scripts:
		function VALIDARRANGOFECHA(myThis)
				{ 	
					if (myThis.TypedValue() > Ctrl("f_fin").TypedValue())
						{
							myThis.SetError('La fecha de inicio es mayor que la fecha de fin');
							return false;						
						}					
						else return true;												
				}					



function VALIDARRANGOFECHAF(myThis)
				{ 
					if (Ctrl("f_ini").TypedValue() == "" && myThis.TypedValue()  != "")
						{
							myThis.SetError('El rango de fechas especificado no es correcto');
							return false;						
						}					
						else return true;												
				}

function Ejecutar()
{               
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("FILTER");
}
